#![allow(unused_imports)]
use std::io;
use std::io::prelude::*;
use std::io::BufReader;
use std::str::FromStr;
use std::collections::{VecDeque, HashMap};

fn main() {
    let stdin = io::stdin();
    let mut input = stdin.lock();
    let mut line = String::new();
    input.read_line(&mut line).unwrap();
    let nums = get_numbers(&line);
    let shovel_price: i32 = nums[0];
    let change = nums[1];

    for i in 1..11 {
        let total = i * shovel_price;
        if total < 10 && total < change {
            continue;
        }

        if total % 10 == 0 || (total - change) % 10 == 0 {
            println!("{}", i);
            return;
        }
    }

    println!("-1");
}

/*
 * Utility Functions
 */

// get numbers from line seperated by spaces
fn get_numbers<T>(line: &str) -> Vec<T>
    where T: FromStr,
          <T as std::str::FromStr>::Err: std::fmt::Debug,
{
    line.split_whitespace()
        .map(|chunk| chunk.parse::<T>().expect("failed to parse"))
        .collect()
}
